mapper.select:
select count(*)
from content_view
where content_type = #{content_type}
  and content_id = #{content_id}
  and member_id = #{member_id}

mapper.update:
update notice
set view_count = ifnull(view_count, 0) + 1
where notice_id = #{notice_id}

update recipe
set view_count = ifnull(view_count, 0) + 1
where recipe_id = #{recipe_id}

update board
set view_count = ifnull(view_count, 0) + 1
where board_id = #{board_id}
